import React from "react";
import { Routes, Route } from "react-router-dom";

// استيراد المكونات والصفحات
import Layout from "./Components/Layout";
import HomePage from "./Pages/HomePage/HomePage";
import AboutUs2 from "./Pages/AboutUs2/AboutUs2";
import ContactUs2 from "./Pages/ContactUs2/ContactUs";
import NotFound from "./Pages/NotFound/NotFound";
import Biscuits from "./Pages/Biscuits/Biscuits";
import Cake from "./Pages/Cake/Cake";
import Products from "./Pages/Products/Products";
import ScrollToTop from "./ScrollToTop";

// ملاحظة: تأكد أن اسم المجلد والملف هو ProductsDetails أو ProductDetails
// قمت هنا باستخدام الاسم الأكثر شيوعاً الذي ظهر في كودك
import ProductDetails from "./Pages/ProductsDetails/ProductsDetails";

function App() {
  return (
    <>
      {/* ScrollToTop يضمن بدء الصفحة من الأعلى عند كل انتقال */}
      <ScrollToTop />

      <Routes>
        {/* الصفحة الرئيسية */}
        <Route
          path="/"
          element={
            <Layout>
              <HomePage />
            </Layout>
          }
        />

        {/* صفحة من نحن */}
        <Route
          path="/AboutUs"
          element={
            <Layout>
              <AboutUs2 />
            </Layout>
          }
        />

        {/* صفحة اتصل بنا */}
        <Route
          path="/ContactUs"
          element={
            <Layout>
              <ContactUs2 />
            </Layout>
          }
        />

        {/* صفحة تصفح البسكويت */}
        <Route
          path="/Biscuits"
          element={
            <Layout>
              <Biscuits />
            </Layout>
          }
        />

        {/* صفحة تصفح الكيك */}
        <Route
          path="/Cake"
          element={
            <Layout>
              <Cake />
            </Layout>
          }
        />

        {/* صفحة المنتجات العامة */}
        <Route
          path="/Products"
          element={
            <Layout>
              <Products />
            </Layout>
          }
        />

        {/* المسار الموحد لتفاصيل المنتج */}
        {/* هذا المسار يستقبل البيانات المرسلة من Cake أو Biscuits عبر الـ state */}
        <Route
          path="/Product/:ProductId"
          element={
            <Layout>
              <ProductDetails />
            </Layout>
          }
        />

        {/* مسار احتياطي لصفحة التفاصيل بدون معرف */}
        <Route
          path="/ProductsDetails"
          element={
            <Layout>
              <ProductDetails />
            </Layout>
          }
        />

        {/* صفحة الخطأ 404 */}
        <Route path="*" element={<NotFound />} />
      </Routes>
    </>
  );
}

export default App;
